\textbf{\textcolor{red}{解一：}}
\begin{align*}
F(s)&=\frac{s + 3}{(s + 1 - j)(s + 1 + j)}=\frac{C_1}{s + 1 - j}+\frac{C_2}{s + 1 + j}\\
C_1&=\lim_{s\to -1 + j}(s + 1 - j)\frac{s + 3}{(s + 1 - j)(s + 1 + j)}=\frac{2 + j}{2j}\\
C_2&=\lim_{s\to -1 - j}(s + 1 + j)\frac{s + 3}{(s + 1 - j)(s + 1 + j)}=\frac{2 - j}{-2j}\\
f(t)&=\frac{2 + j}{2j}e^{(-1 + j)t}-\frac{2 - j}{2j}e^{(-1 - j)t}=\frac{1}{2j}e^{-t}[(2 + j)e^{jt}-(2 - j)e^{-jt}]\\
&=\frac{1}{2j}e^{-t}\left[2j\frac{e^{jt}+e^{-jt}}{2}+4j\frac{e^{jt}-e^{-jt}}{2j}\right]=\frac{1}{2j}e^{-t}\cdot j[2\cos t + 4\sin t]=e^{-t}[\cos t + 2\sin t]
\end{align*}
\textbf{\textcolor{red}{解二：}}
\begin{align*}
F(s)&=\frac{s + 3}{(s + 1)^2 + 1^2}=\frac{s + 1 + 2}{(s + 1)^2 + 1^2}=\frac{s + 1}{(s + 1)^2 + 1^2}+2\frac{1}{(s + 1)^2 + 1^2}\\
f(t)&=e^{-t}\cos t + 2e^{-t}\sin t
\end{align*}

\begin{align*}
F(s)&=\frac{C_2}{(s + 1)^2}+\frac{C_1}{s + 1}+\frac{C_3}{s}+\frac{C_4}{s + 3}\\
C_2&=\lim_{s\rightarrow -1}(s + 1)^2\frac{s + 2}{s(s + 1)^2(s + 3)}=\frac{-1 + 2}{(-1)(-1 + 3)}=-\frac{1}{2}\\
C_1&=\frac{1}{1!}\lim_{s\rightarrow -1}\frac{d}{ds}\left[(s + 1)^2\frac{s + 2}{s(s + 1)^2(s + 3)}\right]=\lim_{s\rightarrow -1}\frac{s(s + 3)-(s + 2)[s + 3 + s]}{s^2(s + 3)^2}=-\frac{3}{4}\\
C_3&=\lim_{s\rightarrow 0}s\cdot\frac{s + 2}{s(s + 1)^2(s + 3)}=\frac{2}{3}\\
C_4&=\lim_{s\rightarrow -3}(s + 3)\frac{s + 2}{s(s + 1)^2(s + 3)}=\frac{1}{12}\\
F(s)&=-\frac{1}{2}\cdot\frac{1}{(s + 1)^2}-\frac{3}{4}\cdot\frac{1}{s + 1}+\frac{2}{3}\cdot\frac{1}{s}+\frac{1}{12}\cdot\frac{1}{s + 3}\\
f(t)&=-\frac{1}{2}te^{-t}-\frac{3}{4}e^{-t}+\frac{2}{3}+\frac{1}{12}e^{-3t}
\end{align*}

\begin{align*}
&由u_r = Ri + u_c，i = C\dot{u}_c可得RC\dot{u}_c + u_c = u_r\\
&进行拉普拉斯变换：RC[sU_c(s) - u_c(0)] + U_c(s) = U_r(s)\\
&整理得(RCs + 1)U_c(s) = U_r(s) + RCu_c(0)\\
&已知U_r(s)=\frac{E_0}{s}，则U_c(s)=\frac{U_r(s)}{RCs + 1}+\frac{RCu_c(0)}{RCs + 1}=\frac{E_0}{s(RCs + 1)}+\frac{RCu_c(0)}{RCs + 1}\\
&进一步变形为U_c(s)=\frac{E_0/RC}{s(s+\frac{1}{RC})}+\frac{u_c(0)}{s+\frac{1}{RC}}=\frac{C_0}{s}+\frac{C_1}{s+\frac{1}{RC}}+\frac{u_c(0)}{s+\frac{1}{RC}}\\
&其中C_0=\lim_{s \to 0}s\frac{E_0/RC}{s(s+\frac{1}{RC})}=E_0，C_1=\lim_{s \to -\frac{1}{RC}}(s+\frac{1}{RC})\frac{E_0/RC}{s(s+\frac{1}{RC})}=-E_0\\
&所以U_c(s)=\frac{E_0}{s}-\frac{E_0}{s+\frac{1}{RC}}+\frac{u_c(0)}{s+\frac{1}{RC}}\\
&进行拉普拉斯反变换得u_c(t)=E_0 - E_0e^{-\frac{1}{RC}t}+u_c(0)\cdot e^{-\frac{1}{RC}t}=E_0 - [E_0 - u_c(0)]\cdot e^{-\frac{1}{RC}t}
\end{align*}

